const savedMessage = $input.first().json;
const replyContext = $('Build API Response').item.json;
let routeContext = { messages: [] };
try {
  routeContext = $('Expose Route Metadata').item.json;
} catch (error) {
  routeContext = { messages: [] };
}
const responseMode = replyContext.response_mode || 'direct_owner_reply';
const messages = Array.isArray(routeContext.messages) ? routeContext.messages : [];
const lastUserFromRoute = [...messages].reverse().find((message) => message.role === 'user');
const latestUserMessage = (lastUserFromRoute?.content || $('Normalize Input').item.json.message || '').trim();
const assistantReply = (replyContext.reply || '').trim();
const memoryTestMode = $('Normalize Input').item.json.memory_test_mode || '';
const taskClass = replyContext.task_class || 'chat';
const meaningfulTechnicalWork = taskClass === 'technical_work'
  && replyContext.command_success === true
  && /(implement|implemented|fix|fixed|update|updated|patch|patched|migrate|migration|refactor|created|added|write|wrote|build|built)/i.test(`${latestUserMessage} ${assistantReply}`)
  && assistantReply.length >= 24;
const explicitMemoryCue = /(decision|architectural decision|architecture decision|environment fact|runtime fact|operational note|runtime note|user preference|durable preference|remember this|preference|for future responses|always|never)/i.test(latestUserMessage);
const delegatedResponse = responseMode.startsWith('delegated_');
const shouldExtractMemory = Boolean(savedMessage.id && assistantReply)
  && !delegatedResponse
  && !replyContext.approval_required
  && replyContext.error_type !== 'approval_required'
  && (taskClass !== 'technical_work' || replyContext.command_success !== false)
  && (explicitMemoryCue || meaningfulTechnicalWork || assistantReply.length >= 40);
const extractionContract = {
  items: [
    {
      scope: 'global|conversation|task',
      memory_type: 'task_summary|decision|environment_fact|operational_note|conversation_summary',
      title: 'short title or empty string',
      summary: 'durable compact summary',
      details_json: {},
      importance: 1,
    },
  ],
};
const extractionPrompt = [
  'You extract durable structured Ghost memory.',
  'Return JSON only. No markdown. No explanation. No surrounding prose.',
  'Return exactly one object with one key: items.',
  'If nothing qualifies, return {"items":[]}.',
  'Each item must contain exactly these keys: scope, memory_type, title, summary, details_json, importance.',
  'Allowed scope: global, conversation, task.',
  'Allowed memory_type: task_summary, decision, environment_fact, operational_note, conversation_summary.',
  'importance must be an integer 1..5.',
  'title should be short. summary should be compact, durable, and under 240 characters.',
  'details_json must be a small object. Use {} when not needed.',
  'Do not store chit-chat, greetings, vague acknowledgements, raw runtime noise, stack traces, banners, code fences, or duplicate restatements.',
  'Prefer decision, environment_fact, operational_note over weak summaries.',
  'Only emit task_summary when meaningful work completed successfully.',
  'Return at most 3 items.',
  '',
  'JSON schema shape:',
  JSON.stringify(extractionContract),
  '',
  'Turn context JSON:',
  JSON.stringify({
    task_class: taskClass,
    provider_used: replyContext.provider_used || '',
    model_used: replyContext.model_used || '',
    command_success: replyContext.command_success,
    risk_level: replyContext.risk_level || 'safe',
    meaningful_technical_work: meaningfulTechnicalWork,
    response_mode: responseMode,
    latest_user_message: latestUserMessage,
    assistant_reply: assistantReply,
  }),
].join('\n');

return [{ json: {
  conversation_id: replyContext.conversation_id || '',
  source_message_id: savedMessage.id || '',
  task_class: taskClass,
  latest_user_message: latestUserMessage,
  assistant_reply: assistantReply,
  memory_test_mode: memoryTestMode,
  should_extract_memory: shouldExtractMemory,
  meaningful_technical_work: meaningfulTechnicalWork,
  extraction_prompt: extractionPrompt,
  memory_debug: {
    extractor_attempted: shouldExtractMemory,
    extractor_skipped: !shouldExtractMemory,
    fallback_used: false,
    candidate_count: 0,
    filtered_count: 0,
    saved_count: 0,
  },
} }];

const response = $input.first().json;
const context = $('Build Memory Extraction Input').item.json;
const allowedScopes = new Set(['global', 'conversation', 'task']);
const allowedTypes = new Set(['task_summary', 'decision', 'environment_fact', 'operational_note', 'conversation_summary']);
const parseOutputText = () => {
  if (typeof response.output_text === 'string' && response.output_text.trim()) return response.output_text.trim();
  if (Array.isArray(response.output)) {
    const text = response.output
      .flatMap((entry) => Array.isArray(entry.content) ? entry.content : [])
      .map((entry) => entry.text || entry.value || '')
      .join('')
      .trim();
    if (text) return text;
  }
  if (typeof response.response === 'string' && response.response.trim()) return response.response.trim();
  return '';
};
const extractJsonText = (text) => {
  if (!text) return '';
  const trimmed = text.trim();
  if (trimmed.startsWith('{') && trimmed.endsWith('}')) return trimmed;
  const start = trimmed.indexOf('{');
  const end = trimmed.lastIndexOf('}');
  return start >= 0 && end > start ? trimmed.slice(start, end + 1) : trimmed;
};
const sanitizeItem = (entry) => ({
  scope: String(entry.scope || '').trim(),
  memory_type: String(entry.memory_type || '').trim(),
  title: entry.title ? String(entry.title).replace(/\s+/g, ' ').trim().slice(0, 160) : '',
  summary: String(entry.summary || '').replace(/\s+/g, ' ').trim().slice(0, 240),
  details_json: entry.details_json && typeof entry.details_json === 'object' && !Array.isArray(entry.details_json) ? entry.details_json : {},
  importance: Number.isFinite(Number(entry.importance)) ? Math.max(1, Math.min(5, Math.round(Number(entry.importance)))) : 3,
});
const hasNoisySummary = (summary) => /```|stack trace|exception:|error:|stderr|stdout|traceback|OpenAI Codex|session id:|tokens used|^hi$|^hello$|^thanks$|^ok$|^okay$|^understood$/i.test(summary);
const normalizedKey = (entry) => `${entry.scope}|${entry.memory_type}|${entry.summary.toLowerCase()}`;
const buildFallbackItems = () => {
  if (context.memory_test_mode === 'invalid_json') return [];
  const userText = String(context.latest_user_message || '').trim();
  const normalizedUser = userText.replace(/\s+/g, ' ').trim();
  const fallbackItems = [];
  const pushFallback = (entry) => fallbackItems.push(entry);
  const preferenceMatch = normalizedUser.match(/(?:user preference(?: for this conversation)?|durable preference|preference|instruction|remember this|for future responses)\s*:\s*(.+)$/i);
  if (preferenceMatch?.[1] && /(always|never|prefer|prefers|avoid|use|do not|don't|keep|concise|verbose|full config files|snippets)/i.test(preferenceMatch[1])) {
    pushFallback({
      scope: 'conversation',
      memory_type: 'decision',
      title: 'Durable preference',
      summary: preferenceMatch[1],
      details_json: { source: 'heuristic_fallback', trigger: 'explicit_preference' },
      importance: 4,
    });
  }
  const prefersSentence = normalizedUser.match(/(the user prefers .+?)(?:\.\s*(remember this preference|remember this|save this preference))?$/i);
  if (prefersSentence?.[1] && /(prefers|avoid|use|do not|don't)/i.test(prefersSentence[1])) {
    pushFallback({
      scope: 'conversation',
      memory_type: 'decision',
      title: 'Durable preference',
      summary: prefersSentence[1],
      details_json: { source: 'heuristic_fallback', trigger: 'preference_sentence' },
      importance: 4,
    });
  }
  const architectureMatch = normalizedUser.match(/(?:architectural decision|architecture decision|decision(?: for this conversation)?)\s*:\s*(.+)$/i);
  if (architectureMatch?.[1] && /(use|prefer|keep|avoid|do not|don't)/i.test(architectureMatch[1])) {
    pushFallback({
      scope: 'conversation',
      memory_type: 'decision',
      title: 'Architectural decision',
      summary: architectureMatch[1],
      details_json: { source: 'heuristic_fallback', trigger: 'explicit_decision' },
      importance: 5,
    });
  }
  const envFactMatch = normalizedUser.match(/(?:environment fact|runtime fact)\s*:\s*(.+)$/i);
  if (envFactMatch?.[1] && envFactMatch[1].length >= 16) {
    pushFallback({
      scope: 'conversation',
      memory_type: 'environment_fact',
      title: 'Environment fact',
      summary: envFactMatch[1],
      details_json: { source: 'heuristic_fallback', trigger: 'explicit_fact' },
      importance: 4,
    });
  }
  const operationalNoteMatch = normalizedUser.match(/(?:operational note|runtime note)\s*:\s*(.+)$/i);
  if (operationalNoteMatch?.[1] && operationalNoteMatch[1].length >= 16) {
    pushFallback({
      scope: 'conversation',
      memory_type: 'operational_note',
      title: 'Operational note',
      summary: operationalNoteMatch[1],
      details_json: { source: 'heuristic_fallback', trigger: 'explicit_operational_note' },
      importance: 4,
    });
  }
  const seen = new Set();
  return fallbackItems.filter((entry) => {
    const key = normalizedKey(sanitizeItem(entry));
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
};

let rawText = parseOutputText();
let parsedItems = [];
let parseStatus = context.should_extract_memory ? 'attempted' : 'skipped';
let parseError = '';
const trimmedJsonText = extractJsonText(rawText);

if (response.error) {
  parseStatus = 'extractor_error';
  parseError = typeof response.error === 'string' ? response.error : (response.error.message || 'memory extractor request failed');
} else if (trimmedJsonText) {
  try {
    const parsed = JSON.parse(trimmedJsonText);
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed) && Array.isArray(parsed.items)) {
      parsedItems = parsed.items;
      parseStatus = 'parsed';
    } else {
      parseStatus = 'invalid_shape';
      parseError = 'Extractor response did not match {items:[...]}';
    }
  } catch (error) {
    parseStatus = 'invalid_json';
    parseError = error.message;
  }
}

let candidateItems = parsedItems
  .filter((entry) => entry && typeof entry === 'object')
  .map(sanitizeItem)
  .filter((entry) => allowedScopes.has(entry.scope) && allowedTypes.has(entry.memory_type) && entry.summary)
  .filter((entry) => JSON.stringify(entry.details_json).length <= 800)
  .filter((entry) => !hasNoisySummary(entry.summary))
  .map((entry) => ({
    ...entry,
    conversation_id: entry.scope === 'conversation' ? (context.conversation_id || null) : null,
    task_run_id: null,
    source_message_id: context.source_message_id || null,
    status: 'active',
  }));

let fallbackUsed = false;
if (!candidateItems.length) {
  const fallbackItems = buildFallbackItems().map((entry) => ({
    ...sanitizeItem(entry),
    conversation_id: context.conversation_id || null,
    task_run_id: null,
    source_message_id: context.source_message_id || null,
    status: 'active',
  }));
  if (fallbackItems.length) {
    candidateItems = fallbackItems;
    fallbackUsed = true;
    parseStatus = parseStatus === 'parsed' ? 'parsed_with_fallback' : 'heuristic_fallback';
  }
}

return [{ json: {
  ...context,
  memory_parse_status: parseStatus,
  memory_parse_error: parseError,
  memory_raw_text: trimmedJsonText.slice(0, 2000),
  memory_candidate_items: candidateItems,
  memory_debug: {
    ...(context.memory_debug || {}),
    extractor_attempted: Boolean(context.should_extract_memory),
    extractor_skipped: !context.should_extract_memory,
    candidate_count: candidateItems.length,
    fallback_used: fallbackUsed,
    parse_status: parseStatus,
  },
} }];

const item = $input.first().json;
const priority = { decision: 100, environment_fact: 90, operational_note: 80, conversation_summary: 40, task_summary: 30 };
const lowerUser = String(item.latest_user_message || '').toLowerCase();
const memoryCandidates = Array.isArray(item.memory_candidate_items) ? item.memory_candidate_items : [];
const meaningfulTaskSummary = item.task_class === 'technical_work'
  && item.meaningful_technical_work === true
  && /(implement|implemented|fix|fixed|update|updated|patch|patched|migrate|migration|refactor|created|added|write|wrote|build|built)/i.test(`${item.latest_user_message} ${item.assistant_reply}`);
const skipPatterns = [/^hello\b/i, /^hi\b/i, /^thanks\b/i, /^thank you\b/i, /^okay\b/i, /^understood\b/i, /^ping\d+$/i, /^say hello/i, /^reply with exactly/i];
const noisePatterns = [/```/, /stack trace/i, /traceback/i, /stderr/i, /stdout/i, /openai codex/i, /session id:/i, /tokens used/i, /error:/i, /exception:/i];
const normalizeWhitespace = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const normalizeClause = (value) => normalizeWhitespace(value).replace(/[.!?]+$/g, '').toLowerCase();
const normalizeTopicText = (value) => normalizeWhitespace(value).toLowerCase().replace(/[^a-z0-9\s:_-]/g, ' ').replace(/\s+/g, ' ').trim();
const conservativeTypes = new Set(['decision', 'environment_fact', 'operational_note']);
const canonicalPunctuationTypes = new Set(['decision', 'environment_fact', 'operational_note']);
const stripWrapperPhrases = (summary, memoryType) => {
  let text = normalizeWhitespace(summary);
  if (!text || !conservativeTypes.has(memoryType)) return text;
  text = text
    .replace(/^(architectural decision|architecture decision|decision(?: for this conversation)?|environment fact|runtime fact|operational note|runtime note|user preference(?: for this conversation)?|durable preference|preference|durable instruction)\s*:\s*/i, '')
    .replace(/^remember\s+(?:that\s+)?/i, '')
    .replace(/^please\s+/i, '')
    .replace(/\s*[.?!]?\s*(confirm briefly|confirm clearly|confirm|briefly confirm|save only the durable decision|save only the durable fact|save only the durable note|save this note|save this preference|remember this preference|remember this note|remember this preference for future responses|keep only the durable decision|keep only the durable fact|keep only the durable note|remember this preference)\s*[.?!]*$/i, '');
  return normalizeWhitespace(text);
};
const collapseDuplicateClauses = (summary, memoryType) => {
  const text = normalizeWhitespace(summary);
  if (!text || !conservativeTypes.has(memoryType)) return text;
  const parts = text.split(/(?<=[.!?])\s+/).map((part) => normalizeWhitespace(part)).filter(Boolean);
  if (!parts.length) return text;
  const deduped = [];
  const seenClauses = new Set();
  for (const part of parts) {
    const key = normalizeClause(part);
    if (!key || seenClauses.has(key)) continue;
    seenClauses.add(key);
    deduped.push(part);
  }
  if (!deduped.length) return text;
  if (deduped.length === 2) {
    const first = normalizeClause(deduped[0]);
    const second = normalizeClause(deduped[1]);
    if (first && second && (first.includes(second) || second.includes(first))) {
      return normalizeWhitespace(first.length <= second.length ? deduped[0] : deduped[1]);
    }
  }
  return normalizeWhitespace(deduped.join(' '));
};
const canonicalizeShortFallbackSummary = (summary, memoryType, detailsJson) => {
  const text = normalizeWhitespace(summary);
  if (!text) return text;
  if (!canonicalPunctuationTypes.has(memoryType)) return text;
  if (!detailsJson || detailsJson.source !== 'heuristic_fallback') return text;
  if (text.length > 120) return text;
  if (/[?;:]$/.test(text)) return text;
  return normalizeWhitespace(text.replace(/[.!]+$/g, ''));
};
const normalizeSummary = (summary, memoryType, detailsJson) => {
  const original = normalizeWhitespace(summary);
  if (!original) return '';
  let cleaned = stripWrapperPhrases(original, memoryType);
  cleaned = collapseDuplicateClauses(cleaned, memoryType);
  cleaned = stripWrapperPhrases(cleaned, memoryType);
  cleaned = canonicalizeShortFallbackSummary(cleaned, memoryType, detailsJson);
  cleaned = normalizeWhitespace(cleaned);
  if (!cleaned) return original;
  if (cleaned.length < 12 && original.length >= 12) return original;
  return cleaned;
};
const deriveTopicKey = (summary, memoryType) => {
  const normalized = normalizeTopicText(summary);
  if (!normalized || !conservativeTypes.has(memoryType)) return '';
  if (memoryType === 'environment_fact') {
    const subjectMatch = normalized.match(/^(?:the\s+)?(.+?)\s+(uses|is|runs|has|requires|needs|supports|remains|stays)\b/);
    if (subjectMatch?.[1]) return `environment_fact:${subjectMatch[1].trim().slice(0, 64)}`;
  }
  if (memoryType === 'operational_note') {
    const opMatch = normalized.match(/^(restart|reload|publish|deploy|run|use)\s+(.+?)(?:\s+(after|before|when|for)\b|$)/);
    if (opMatch?.[1] && opMatch?.[2]) return `operational_note:${opMatch[1]}:${opMatch[2].trim().slice(0, 64)}`;
  }
  return `exact:${memoryType}:${normalized.slice(0, 120)}`;
};
const decorateDetailsJson = (entry, summary) => {
  const details = entry.details_json && typeof entry.details_json === 'object' && !Array.isArray(entry.details_json)
    ? { ...entry.details_json }
    : {};
  const topicKey = deriveTopicKey(summary, entry.memory_type);
  if (topicKey) details.topic_key = topicKey;
  if (entry.memory_type === 'decision' && ['explicit_preference', 'preference_sentence'].includes(String(details.trigger || ''))) {
    details.memory_origin = 'durable_user_preference';
  }
  return details;
};
const normalizeKey = (entry) => {
  const details = entry.details_json && typeof entry.details_json === 'object' && !Array.isArray(entry.details_json) ? entry.details_json : {};
  const topicKey = normalizeWhitespace(details.topic_key || '');
  return `${entry.scope}|${entry.memory_type}|${(topicKey || String(entry.summary || '').toLowerCase())}`;
};
const filteredOut = [];
const normalizationChanges = [];
const seen = new Set();
const filtered = memoryCandidates.map((entry) => {
  const originalSummary = normalizeWhitespace(entry.summary || '');
  const normalizedSummary = normalizeSummary(originalSummary, entry.memory_type, entry.details_json || {});
  const nextSummary = normalizedSummary || originalSummary;
  const nextDetailsJson = decorateDetailsJson(entry, nextSummary);
  if (originalSummary && nextSummary && originalSummary !== nextSummary) {
    normalizationChanges.push({ memory_type: entry.memory_type, before: originalSummary, after: nextSummary });
  }
  return { ...entry, summary: nextSummary, details_json: nextDetailsJson };
}).filter((entry) => {
  const summary = normalizeWhitespace(entry.summary || '');
  const key = normalizeKey({ ...entry, summary });
  if (!summary) { filteredOut.push({ reason: 'empty_summary', key }); return false; }
  if (summary.length < 16) { filteredOut.push({ reason: 'too_short', key }); return false; }
  if (skipPatterns.some((pattern) => pattern.test(summary)) || skipPatterns.some((pattern) => pattern.test(lowerUser))) { filteredOut.push({ reason: 'trivial_chitchat', key }); return false; }
  if (noisePatterns.some((pattern) => pattern.test(summary))) { filteredOut.push({ reason: 'runtime_noise', key }); return false; }
  if (entry.memory_type === 'task_summary' && !meaningfulTaskSummary) { filteredOut.push({ reason: 'weak_task_summary', key }); return false; }
  if (seen.has(key)) { filteredOut.push({ reason: 'duplicate_in_pass', key }); return false; }
  seen.add(key);
  return true;
}).sort((a, b) => (priority[b.memory_type] || 0) - (priority[a.memory_type] || 0)).slice(0, 3);

return [{ json: {
  ...item,
  memory_items: filtered,
  memory_debug: {
    ...(item.memory_debug || {}),
    candidate_count: memoryCandidates.length,
    filtered_count: filtered.length,
    filtered_out_count: filteredOut.length,
    filtered_out_reasons: filteredOut.slice(0, 10),
    normalization_changes: normalizationChanges.slice(0, 10),
  },
} }];

const rows = $input.all().map((entry) => entry.json || {});
const context = $('Filter Structured Memory Candidates').item.json;
const savedRows = rows.filter((row) => !row.error && row.id);
const supersededCount = savedRows.length ? Number(savedRows[0].superseded_count || 0) : 0;
return [{ json: {
  conversation_id: context.conversation_id || '',
  source_message_id: context.source_message_id || '',
  memory_debug: {
    ...(context.memory_debug || {}),
    saved_count: savedRows.length,
    superseded_count: supersededCount,
    saved_items: savedRows.map((row) => ({
      id: row.id,
      scope: row.scope,
      memory_type: row.memory_type,
      summary: row.summary,
    })),
  },
} }];
